const body = $json.body ?? $json;

const title = body.title ?? 'New Playlist';
const description = body.description ?? '';

let songs = body.songs ?? body.list ?? body.tracks;

// Allow songs as newline-separated string
if (typeof songs === 'string') {
  songs = songs
    .split('\n')
    .map(s => s.trim())
    .filter(Boolean);
}

if (!Array.isArray(songs)) songs = [];

if (!songs.length) {
  throw new Error('No songs provided. Provide body.songs as an array or newline-separated string.');
}

// Target player entity_id (required for MA play_media)
// IMPORTANT: Use the _2 suffix players (e.g., media_player.office_2) - these are the MA versions
const playerId = body.player_id ?? body.playerId ?? body.entity_id ?? 'media_player.office_2';

// Enqueue mode: 'play' (replace & play), 'add' (append), 'next' (play next)
const enqueue = body.enqueue ?? 'play';

return [{
  title,
  description,
  songs,
  playerId,
  enqueue,
  songCount: songs.length
}];

// Explode songs for batch processing
const inputData = $json;
const songs = inputData.songs;
const playerId = inputData.playerId;
const enqueue = inputData.enqueue;
const title = inputData.title;

return songs.map((song, index) => ({
  song,
  songIndex: index,
  playerId,
  // First track uses specified enqueue mode, rest use 'add' to append
  enqueue: index === 0 ? enqueue : 'add',
  title,
  isFirstSong: index === 0,
  isLastSong: index === songs.length - 1,
  totalSongs: songs.length
}));

// Get batch context
const ctx = $items('Split In Batches')[0]?.json ?? {};
const song = ctx.song;
const songIndex = ctx.songIndex;
const playerId = ctx.playerId;
const enqueue = ctx.enqueue;
const isLastSong = ctx.isLastSong;
const title = ctx.title;

// Parse search results from HA service response
const response = $json;
const serviceResponse = response.service_response ?? response;

let tracks = serviceResponse.tracks ?? [];

// Get first matching track
const firstTrack = tracks[0] ?? null;

let trackUri = null;
let trackName = null;
let trackArtist = null;
let found = false;

if (firstTrack) {
  trackUri = firstTrack.uri ?? null;
  trackName = firstTrack.name ?? null;
  trackArtist = firstTrack.artists?.[0]?.name ?? null;
  found = Boolean(trackUri);
}

return [{
  song,
  songIndex,
  playerId,
  enqueue,
  trackUri,
  trackName,
  trackArtist,
  found,
  isLastSong,
  title
}];

// Pass through for batch continuation
const ctx = $items('Split In Batches')[0]?.json ?? $json;
return [{
  ...ctx,
  queued: true
}];

// Pass through for not found
const ctx = $items('Split In Batches')[0]?.json ?? $json;
return [{
  ...ctx,
  queued: false
}];

// Collect all results and summarize
const allResults = $items('Pick Track');

const added = [];
const missing = [];

for (const item of allResults) {
  const j = item.json;
  if (j.found) {
    added.push({
      song: j.song,
      trackUri: j.trackUri,
      trackName: j.trackName,
      trackArtist: j.trackArtist
    });
  } else {
    missing.push({ song: j.song });
  }
}

const firstResult = allResults[0]?.json ?? {};

return [{
  success: true,
  title: firstResult.title,
  playerId: firstResult.playerId,
  addedCount: added.length,
  missingCount: missing.length,
  added,
  missing
}];
